const lead = $('Set: Normalize Lead').item.json;
const system = $('Set: AI Config').item.json.system_prompt;
const userMessage =
  "New lead submitted:\n" +
  "Name: " + (lead.name || "(none)") + "\n" +
  "Phone: " + (lead.phone || "(none)") + "\n" +
  "Email: " + (lead.email || "(none)") + "\n" +
  "Treatment interest: " + (lead.treatment_interest || "(none)");
return [{ json: { system, userMessage } }];

let raw = "";
try { raw = $json.content[0].text || ""; } catch (e) { raw = ""; }

let parsed = null;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch (e2) { parsed = null; } }
}

if (!parsed || (typeof parsed.qualified === "undefined" && typeof parsed.status === "undefined")) {
  parsed = {
    qualified: false,
    status: "needs_info",
    reason: "AI response was unparseable; defaulted to follow-up.",
    missing_info: ["incident details"],
    sms_reply: "Thanks for reaching out! Could you share a few details about the treatment you're interested in, so we can help?"
  };
}

const allowed = ["qualified", "needs_info", "declined"];
let status = String(parsed.status || "").toLowerCase().trim();
if (!allowed.includes(status)) {
  status = parsed.qualified === true ? "qualified" : "needs_info";
}
const qualified = status === "qualified";

return [{ json: {
  qualified: qualified,
  status: status,
  reason: String(parsed.reason || ""),
  missing_info: Array.isArray(parsed.missing_info) ? parsed.missing_info : [],
  sms_reply: String(parsed.sms_reply || "Thanks for reaching out — a team member will follow up shortly.")
} }];

const lead = $('Set: Normalize Lead').item.json;
const tz = "America/New_York";
const days = 14;
const now = DateTime.now().setZone(tz);
let pref = null;
if (lead.preferred_date) {
  const p = DateTime.fromISO(lead.preferred_date, { zone: tz });
  if (p.isValid) pref = p.startOf('day');
}
const startDt = (pref && pref > now) ? pref : now;
const timeMin = startDt.toISO();
const timeMax = startDt.plus({ days: days }).endOf('day').toISO();
return [{ json: { timeMin, timeMax } }];

const lead = $('Set: Normalize Lead').item.json;
const ai = $('Code: Parse AI JSON').item.json;
const tz = "America/New_York";
const startHour = 9;
const endHour = 17;
const duration = 30;
const interval = 30;
const slotsToShow = 6;
const days = 14;

const events = $input.all().map(i => i.json).filter(Boolean);
const busy = [];
for (const ev of events) {
  if (!ev || ev.status === 'cancelled' || ev.transparency === 'transparent') continue;
  const s = ev.start && (ev.start.dateTime || ev.start.date);
  const e = ev.end && (ev.end.dateTime || ev.end.date);
  if (!s || !e) continue;
  busy.push([DateTime.fromISO(s, { zone: tz }), DateTime.fromISO(e, { zone: tz })]);
}
function overlaps(s, e) { return busy.some(([bs, be]) => s < be && e > bs); }

const now = DateTime.now().setZone(tz).plus({ minutes: 60 });
let pref = null;
if (lead.preferred_date) {
  const p = DateTime.fromISO(lead.preferred_date, { zone: tz });
  if (p.isValid) pref = p.startOf('day');
}
let dt = (pref && pref > now) ? pref : now;
dt = dt.set({ minute: 0, second: 0, millisecond: 0 });

const out = [];
const limit = dt.plus({ days: days });
let guard = 0;
while (out.length < slotsToShow && dt < limit && guard < 8000) {
  guard++;
  if (dt.weekday > 5) { dt = dt.plus({ days: 1 }).set({ hour: startHour, minute: 0, second: 0, millisecond: 0 }); continue; }
  if (dt.hour < startHour) { dt = dt.set({ hour: startHour, minute: 0, second: 0, millisecond: 0 }); }
  const dayEnd = dt.set({ hour: endHour, minute: 0, second: 0, millisecond: 0 });
  if (dt.plus({ minutes: duration }) > dayEnd) { dt = dt.plus({ days: 1 }).set({ hour: startHour, minute: 0, second: 0, millisecond: 0 }); continue; }
  if (dt < now) { dt = dt.plus({ minutes: interval }); continue; }
  const slotEnd = dt.plus({ minutes: duration });
  if (!overlaps(dt, slotEnd)) out.push({ iso: dt.toISO(), label: dt.toFormat("cccc, LLL d 'at' h:mm a") });
  dt = dt.plus({ minutes: interval });
}

return [{ json: { qualified: ai.qualified, status: ai.status, sms_reply: ai.sms_reply, reason: ai.reason, slots: out } }];

const lead = $('Set: Normalize Lead').item.json;
const tz = "America/New_York";
const duration = 30;
const parsed = DateTime.fromISO(lead.chosen_slot || "", { zone: tz });
const valid = parsed.isValid;
const s = valid ? parsed : DateTime.now().setZone(tz);
const startISO = s.toISO();
const endISO = s.plus({ minutes: duration }).toISO();
return [{ json: { timeMin: startISO, timeMax: endISO, startISO, endISO, human: s.toFormat("cccc, LLL d 'at' h:mm a"), valid } }];

const tz = "America/New_York";
const bw = $('Code: Book Window').item.json;
const start = DateTime.fromISO(bw.startISO, { zone: tz });
const end = DateTime.fromISO(bw.endISO, { zone: tz });
const events = $input.all().map(i => i.json).filter(Boolean);
let free = bw.valid !== false;
for (const ev of events) {
  if (!ev || ev.status === 'cancelled' || ev.transparency === 'transparent') continue;
  const s = ev.start && (ev.start.dateTime || ev.start.date);
  const e = ev.end && (ev.end.dateTime || ev.end.date);
  if (!s || !e) continue;
  const bs = DateTime.fromISO(s, { zone: tz });
  const be = DateTime.fromISO(e, { zone: tz });
  if (start < be && end > bs) { free = false; break; }
}
return [{ json: { free, startISO: bw.startISO, endISO: bw.endISO, human: bw.human } }];

const lead = $('Set: Normalize Lead').item.json;
const vf = $('Code: Verify Free').item.json;
const firm = "Glow Aesthetics Med Spa";
const first = (lead.name || "").trim().split(/\s+/)[0] || "there";
const sms = "Thanks " + first + "! Your free consult with " + firm + " is booked for " + vf.human + ". See you then!";
return [{ json: { sms_reply: sms, human: vf.human } }];
